  PROBLEM = 'PROBLEM',
  INITIATIVE = 'INITIATIVE'
}

export interface Milestone {
  id: string;
  title: string;
  description: string;
  isCompleted: boolean;
  dueDate?: string;
}

export interface Comment {
  id: string;
  author: string;
  text: string;
  timestamp: string;
  votes: number;
}

export interface ImpactEntry {
  id: string;
  type: ImpactType;
  title: string;
  description: string;
  author: string;
  location: string;
  region: string;
  timestamp: string;
  votes: number;
  tags: string[];
  comments: Comment[];
