  participantsCount?: number;
  participantsList?: string[]; // IDs of users who joined
  status?: 'active' | 'completed' | 'on-hold' | 'needs-solution';
  linkedProblemId?: string; // If this is an initiative born from a problem
  linkedInitiativeIds?: string[]; // If this is a problem that has proposed initiatives
}

export interface UserLocation {
  lat: number;
  lng: number;
  name: string;
}

import React from 'react';
import { ImpactEntry, ImpactType } from '../types';
import { MessageSquare, ArrowBigUp, ArrowBigDown, MapPin, Users, CheckCircle, Lightbulb, UserPlus } from 'lucide-react';

interface Props {
  entry: ImpactEntry;
  onVote: (id: string, delta: number) => void;
  onClick: (id: string) => void;
  onJoin?: (id: string) => void;
  isJoined?: boolean;
}

const ImpactCard: React.FC<Props> = ({ entry, onVote, onClick, onJoin, isJoined }) => {
  const isProblem = entry.type === ImpactType.PROBLEM;

  return (
    <div 
      className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden hover:border-indigo-300 transition-all cursor-pointer group hover:shadow-md"
      onClick={() => onClick(entry.id)}
    >
      <div className="flex">
        {/* Vote Sidebar */}
        <div className="bg-slate-50 w-14 flex flex-col items-center py-4 space-y-2 border-r border-slate-100">
          <button 
            onClick={(e) => { e.stopPropagation(); onVote(entry.id, 1); }}
            className="text-slate-400 hover:text-orange-600 transition-colors p-1"
          >
            <ArrowBigUp size={24} fill={entry.votes > 150 ? "currentColor" : "none"} />
          </button>
          <span className="font-bold text-slate-700 text-sm">{entry.votes}</span>
          <button 
            onClick={(e) => { e.stopPropagation(); onVote(entry.id, -1); }}
            className="text-slate-400 hover:text-indigo-600 transition-colors p-1"
          >
            <ArrowBigDown size={24} />
          </button>
        </div>

        {/* Content */}
        <div className="p-5 flex-1">
          <div className="flex items-center justify-between mb-2">
            <div className="flex items-center space-x-2 text-xs text-slate-500">
              <span className={`px-2 py-0.5 rounded-full font-bold uppercase tracking-wider ${
                isProblem ? 'bg-red-100 text-red-700' : 'bg-emerald-100 text-emerald-700'
              }`}>
                {entry.type}
              </span>
              <span>• u/{entry.author}</span>
              <span className="hidden sm:inline">• {entry.timestamp}</span>
            </div>
            {isJoined && (
              <span className="flex items-center gap-1 text-[10px] font-bold text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full border border-emerald-100">
                <CheckCircle size={10} /> JOINED
              </span>
            )}
          </div>

          <h3 className="text-xl font-bold text-slate-900 group-hover:text-indigo-600 transition-colors mb-2 leading-tight">
            {entry.title}
          </h3>

          <p className="text-slate-600 text-sm line-clamp-2 mb-4 leading-relaxed">
            {entry.description}
          </p>

          <div className="flex flex-wrap gap-2 mb-5">
            {entry.tags.map(tag => (
              <span key={tag} className="text-[10px] font-bold uppercase tracking-wide bg-slate-100 text-slate-500 px-2 py-1 rounded">
                #{tag}
              </span>
            ))}
          </div>

          <div className="flex items-center justify-between text-slate-500 text-xs border-t border-slate-100 pt-4">
            <div className="flex items-center space-x-4">
              <div className="flex items-center space-x-1.5">
                <MessageSquare size={16} className="text-slate-400" />
                <span className="font-medium">{entry.comments.length}</span>
              </div>
              <div className="flex items-center space-x-1.5">
                <MapPin size={16} className="text-slate-400" />
                <span className="font-medium">{entry.location}</span>
              </div>
              {isProblem && entry.linkedInitiativeIds && entry.linkedInitiativeIds.length > 0 && (
                <div className="flex items-center space-x-1.5 text-amber-600 bg-amber-50 px-2 py-0.5 rounded-md font-bold">
                  <Lightbulb size={14} />
                  <span>{entry.linkedInitiativeIds.length} Solutions</span>
                </div>
              )}
              {!isProblem && (
                <div className="flex items-center space-x-1.5">
                  <Users size={16} className="text-slate-400" />
                  <span className="font-medium">{(entry.participantsCount || 0) + (isJoined ? 1 : 0)} Joined</span>
                </div>
              )}
            </div>

            {!isProblem && !isJoined && (
              <button 
                onClick={(e) => { e.stopPropagation(); onJoin?.(entry.id); }}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-indigo-50 text-indigo-600 font-bold rounded-lg hover:bg-indigo-600 hover:text-white transition-all border border-indigo-100"
              >
                <UserPlus size={14} /> Join
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

