const Feed = ({ entries, joinedIds, onVote, onViewDetail, onJoin }: { 
  entries: ImpactEntry[], 
  joinedIds: Set<string>,
  onVote: any, 
  onViewDetail: any,
  onJoin: any
}) => {
  const [filter, setFilter] = useState<'all' | 'problems' | 'initiatives'>('all');

  const filteredEntries = useMemo(() => {
    if (filter === 'problems') return entries.filter(e => e.type === ImpactType.PROBLEM);
    if (filter === 'initiatives') return entries.filter(e => e.type === ImpactType.INITIATIVE);
    return entries;
  }, [entries, filter]);

  return (
    <div className="space-y-6 max-w-2xl mx-auto py-6 px-4">
      <div className="flex items-center justify-between mb-2">
        <div>
          <h2 className="text-2xl font-black text-slate-800 tracking-tight">Community Feed</h2>
          <p className="text-slate-500 text-sm font-medium">Prioritizing {filter === 'all' ? 'everything' : filter} in your area</p>
        </div>
        <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200">
          <button 
            onClick={() => setFilter('all')}
            className={`px-3 py-1 text-xs font-bold rounded-lg transition-all ${filter === 'all' ? 'bg-white shadow-sm text-indigo-600' : 'text-slate-500'}`}
          >All</button>
          <button 
            onClick={() => setFilter('problems')}
            className={`px-3 py-1 text-xs font-bold rounded-lg transition-all ${filter === 'problems' ? 'bg-white shadow-sm text-red-600' : 'text-slate-500'}`}
          >Problems</button>
          <button 
            onClick={() => setFilter('initiatives')}
            className={`px-3 py-1 text-xs font-bold rounded-lg transition-all ${filter === 'initiatives' ? 'bg-white shadow-sm text-emerald-600' : 'text-slate-500'}`}
          >Initiatives</button>
        </div>
      </div>

      <div className="space-y-4">
        {filteredEntries.map(entry => (
          <ImpactCard 
            key={entry.id} 
            entry={entry} 
            onVote={onVote} 
            onClick={onViewDetail} 
            onJoin={onJoin}
            isJoined={joinedIds.has(entry.id)}
          />
        ))}
        {filteredEntries.length === 0 && (
          <div className="py-20 text-center bg-white rounded-2xl border-2 border-dashed border-slate-200">
            <Search className="mx-auto text-slate-300 mb-4" size={48} />
