const Feed = ({ entries, joinedIds, onVote, onViewDetail, onJoin }: { 
  entries: ImpactEntry[], 
  joinedIds: Set<string>,
  onVote: any, 
  onViewDetail: any,
  onJoin: any
}) => {
  const [filter, setFilter] = useState<'all' | 'problems' | 'initiatives'>('all');

  const filteredEntries = useMemo(() => {
    if (filter === 'problems') return entries.filter(e => e.type === ImpactType.PROBLEM);
    if (filter === 'initiatives') return entries.filter(e => e.type === ImpactType.INITIATIVE);
    return entries;
