  const [joinedIds, setJoinedIds] = useState<Set<string>>(new Set());
  const [createConfig, setCreateConfig] = useState<{type?: ImpactType, title?: string, problemId?: string}>({});

  const navigate = useNavigate();

  const handleVote = (id: string, delta: number) => {
    setEntries(prev => prev.map(e => e.id === id ? { ...e, votes: e.votes + delta } : e));
  };

  const handleJoin = (id: string) => {
    setJoinedIds(prev => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const handleToggleMilestone = (milestoneId: string) => {
    if (!selectedId) return;
    setEntries(prev => prev.map(entry => {
      if (entry.id !== selectedId || !entry.milestones) return entry;
      return {
        ...entry,
        milestones: entry.milestones.map(m => m.id === milestoneId ? { ...m, isCompleted: !m.isCompleted } : m)
      };
    }));
  };

  const handleProposeInitiative = (problem: ImpactEntry) => {
    setCreateConfig({
      type: ImpactType.INITIATIVE,
      title: `Solution for: ${problem.title}`,
      problemId: problem.id
    });
    setIsModalOpen(true);
  };

  const handlePost = async (partial: Partial<ImpactEntry>) => {
    let milestones: Milestone[] = [];
    if (partial.type === ImpactType.INITIATIVE) {
      milestones = await generateMilestones(partial.title!, partial.description!);
    }

    const newId = Date.now().toString();
    const newEntry: ImpactEntry = {
      id: newId,
      type: partial.type!,
      title: partial.title!,
      description: partial.description!,
      author: 'you',
      location: 'Oakwood, Central',
      region: 'Central',
      timestamp: 'Just now',
      votes: 1,
      tags: partial.tags || [],
      comments: [],
      participantsCount: partial.type === ImpactType.INITIATIVE ? 1 : 0,
      milestones: partial.type === ImpactType.INITIATIVE ? milestones : undefined,
      status: 'active',
      linkedProblemId: createConfig.problemId
    };

    setEntries(prev => {
      let updated = [newEntry, ...prev];
      if (createConfig.problemId) {
        updated = updated.map(e => {
          if (e.id === createConfig.problemId) {
            return { ...e, linkedInitiativeIds: [...(e.linkedInitiativeIds || []), newId] };
          }
          return e;
        });
      }
      return updated;
    });

    setIsModalOpen(false);
    setCreateConfig({});
    if (partial.type === ImpactType.INITIATIVE) handleJoin(newId);
  };

  const handleAddComment = (entryId: string, text: string) => {
    const comment = {
      id: Date.now().toString(),
      author: 'you',
      text,
      timestamp: 'Just now',
      votes: 0
    };
    setEntries(prev => prev.map(e => e.id === entryId ? { ...e, comments: [comment, ...e.comments] } : e));
  };

  const selectedEntry = entries.find(e => e.id === selectedId);
  const linkedEntries = selectedEntry?.linkedInitiativeIds 
    ? entries.filter(e => selectedEntry.linkedInitiativeIds?.includes(e.id))
    : undefined;

  return (
    <div className="min-h-screen flex flex-col selection:bg-indigo-100 selection:text-indigo-900">
      {/* Navbar */}
      <nav className="sticky top-0 z-40 bg-white/90 backdrop-blur-xl border-b border-slate-200/60">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-12">
            <div 
              className="flex items-center gap-3 cursor-pointer group" 
              onClick={() => { setSelectedId(null); navigate('/'); }}
            >
              <div className="w-10 h-10 sm:w-12 sm:h-12 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-xl shadow-indigo-100 group-hover:scale-105 transition-transform">
                <Globe className="text-white" size={24} />
              </div>
              <div>
                <span className="text-xl sm:text-2xl font-black text-slate-800 tracking-tighter leading-none block">ImpactHack</span>
                <span className="text-[10px] font-black text-indigo-500 uppercase tracking-widest mt-0.5 block">Community Action</span>
              </div>
            </div>

            <div className="hidden lg:flex items-center bg-slate-50 rounded-2xl px-5 py-2.5 border border-slate-200 w-[400px] focus-within:bg-white focus-within:border-indigo-400 transition-all">
              <Search className="text-slate-400" size={20} />
              <input 
                placeholder="Find problems or initiatives near you..." 
                className="bg-transparent border-none outline-none text-sm px-3 w-full text-slate-600 font-medium"
              />
              <Filter className="text-slate-300 ml-2" size={16} />
            </div>
          </div>

          <div className="flex items-center gap-4 sm:gap-6">
            <div className="hidden sm:flex items-center gap-2 text-slate-400 bg-slate-100 px-3 py-1.5 rounded-xl border border-slate-200">
               <MapPin size={16} className="text-indigo-400" />
               <span className="text-[10px] font-black uppercase tracking-widest">Oakwood Region</span>
            </div>
            <button 
              onClick={() => { setCreateConfig({}); setIsModalOpen(true); }}
              className="hidden sm:flex items-center gap-2 bg-indigo-600 text-white px-6 py-3 rounded-2xl font-black text-sm hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 active:scale-95"
            >
              <PlusCircle size={20} /> Post Impact
            </button>
            <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-2xl bg-slate-200 border-2 border-slate-50 cursor-pointer overflow-hidden shadow-sm hover:ring-4 ring-indigo-50 transition-all">
              <img src="https://picsum.photos/100/100?seed=user88" alt="User" />
            </div>
          </div>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-1 max-w-7xl mx-auto w-full flex gap-12 p-4 sm:p-6 lg:p-12">
        {/* Left Sidebar - Navigation */}
        <div className="hidden md:block w-64 shrink-0 space-y-1.5 sticky top-32 h-fit">
          <Link to="/" onClick={() => setSelectedId(null)} className={`flex items-center gap-4 px-5 py-3 font-black rounded-2xl transition-all ${!selectedId ? 'bg-indigo-50 text-indigo-700 shadow-sm border border-indigo-100' : 'text-slate-500 hover:bg-slate-50'}`}>
            <Home size={22} /> Feed
          </Link>
          <button className="w-full flex items-center gap-4 px-5 py-3 text-slate-500 font-black rounded-2xl hover:bg-slate-50 transition-all">
            <MapIcon size={22} /> Local Map
          </button>
          <button className="w-full flex items-center gap-4 px-5 py-3 text-slate-500 font-black rounded-2xl hover:bg-slate-50 transition-all">
            <Layout size={22} /> Dashboard
          </button>
          <button className="w-full flex items-center justify-between px-5 py-3 text-slate-500 font-black rounded-2xl hover:bg-slate-50 transition-all">
            <div className="flex items-center gap-4"><UserCheck size={22} /> Joined</div>
            <span className="text-[10px] bg-slate-200 text-slate-600 px-2 py-0.5 rounded-full">{joinedIds.size}</span>
          </button>

          <div className="pt-8 mt-8 border-t border-slate-100">
            <p className="px-5 text-[10px] font-black text-slate-300 uppercase tracking-[0.2em] mb-4">My Regions</p>
            <button className="w-full flex items-center gap-3 px-5 py-2 text-slate-500 text-sm font-bold hover:text-indigo-600 transition-colors">#OakwoodCentral</button>
            <button className="w-full flex items-center gap-3 px-5 py-2 text-slate-500 text-sm font-bold hover:text-indigo-600 transition-colors">#RiverdaleWest</button>
          </div>
        </div>

        {/* Dynamic Center Column */}
        <div className="flex-1 min-w-0">
          {selectedId && selectedEntry ? (
            <DetailView 
              entry={selectedEntry} 
              isJoined={joinedIds.has(selectedEntry.id)}
              onVote={handleVote} 
              onToggleMilestone={handleToggleMilestone}
              onBack={() => setSelectedId(null)}
              onAddComment={handleAddComment}
              onJoin={handleJoin}
              onProposeInitiative={handleProposeInitiative}
              linkedEntries={linkedEntries}
            />
          ) : (
            <Feed 
              entries={entries} 
              joinedIds={joinedIds}
              onVote={handleVote} 
              onViewDetail={setSelectedId} 
              onJoin={handleJoin}
            />
          )}
        </div>

        {/* Right Sidebar - Info */}
        {!selectedId && <Sidebar entries={entries} />}
      </main>

      {/* Mobile Actions */}
      <div className="sm:hidden fixed bottom-8 right-8 flex flex-col gap-4 z-40">
        <button 
          onClick={() => { setCreateConfig({}); setIsModalOpen(true); }}
          className="w-16 h-16 bg-indigo-600 text-white rounded-3xl shadow-2xl flex items-center justify-center hover:scale-105 active:scale-95 transition-transform"
        >
          <PlusCircle size={32} />
        </button>
      </div>

      <CreateModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        onSubmit={handlePost} 
        initialType={createConfig.type}
        prefilledTitle={createConfig.title}
      />
    </div>
  );
};

