import { GoogleGenAI, Type } from "@google/genai";
import { Milestone } from "../types.ts";

const getAI = () => {
  // Use a safe check for process.env
  const apiKey = typeof process !== 'undefined' ? process.env.API_KEY : undefined;
  if (!apiKey) {
    console.warn("ImpactHack: API Key is missing. AI features will fail.");
  }
  return new GoogleGenAI({ apiKey: apiKey || '' });
};

export const analyzeProblem = async (problemDescription: string) => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze the following local problem and suggest tags, severity (1-10), and potential solution approaches: "${problemDescription}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            tags: { type: Type.ARRAY, items: { type: Type.STRING } },
            severity: { type: Type.NUMBER },
            suggestedInitiatives: { 
              type: Type.ARRAY, 
              items: { 
                type: Type.OBJECT,
                properties: {
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["title", "description"]
              } 
            }
          },
          required: ["tags", "severity", "suggestedInitiatives"]
        }
      }
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini analyzeProblem error:", error);
    return { tags: ['general'], severity: 5, suggestedInitiatives: [] };
  }
};

export const generateMilestones = async (initiativeTitle: string, description: string): Promise<Milestone[]> => {
  try {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate a 5-step milestone roadmap for this local initiative: "${initiativeTitle}". Description: ${description}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              description: { type: Type.STRING }
            },
            required: ["title", "description"]
          }
        }
      }
    });

    const raw = JSON.parse(response.text || '[]');
    return raw.map((m: any, idx: number) => ({
      id: `m-${idx}-${Date.now()}`,
      title: m.title,
      description: m.description,
      isCompleted: false
    }));
  } catch (error) {
    console.error("Gemini generateMilestones error:", error);
    return [
      { id: 'm1', title: 'Initial Planning', description: 'Basic research and goal setting.', isCompleted: false },
      { id: 'm2', title: 'Community Outreach', description: 'Finding volunteers.', isCompleted: false }
    ];
  }
};

