              {isProblem && entry.linkedInitiativeIds && entry.linkedInitiativeIds.length > 0 && (
                <div className="flex items-center space-x-1.5 text-gray-900 bg-gray-100 px-2 py-1 rounded-md">
                  <Lightbulb size={12} />
                  <span>{entry.linkedInitiativeIds.length} Linked</span>
                </div>
              )}
            </div>

            {!isProblem && !isJoined && (
              <button 
                onClick={(e) => { e.stopPropagation(); onJoin?.(entry.id); }}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-900 text-white font-black rounded-lg hover:bg-black transition-all"
              >
                <UserPlus size={14} /> Join
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

