import React from 'react';
import { Milestone } from '../types.ts';
import { CheckCircle2, Circle, Clock } from 'lucide-react';

interface Props {
  milestones: Milestone[];
  onToggle: (milestoneId: string) => void;
}

const MilestoneTracker: React.FC<Props> = ({ milestones, onToggle }) => {
  const completedCount = milestones.filter(m => m.isCompleted).length;
  const progress = (completedCount / milestones.length) * 100;

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-end mb-2">
        <h4 className="font-black text-gray-900 flex items-center gap-2 uppercase text-xs tracking-widest">
          <Clock size={16} /> Roadmap Progress
        </h4>
        <span className="text-xs font-black text-gray-500">{Math.round(progress)}% Complete</span>
      </div>

      <div className="w-full bg-gray-200 rounded-full h-1.5">
        <div 
          className="bg-gray-900 h-1.5 rounded-full transition-all duration-700" 
          style={{ width: `${progress}%` }}
        />
      </div>

      <div className="space-y-3 mt-6">
        {milestones.map((m, idx) => (
          <div 
            key={m.id} 
            className={`flex items-start gap-4 p-4 rounded-xl border transition-all ${
              m.isCompleted ? 'bg-gray-50 border-gray-200' : 'bg-white border-gray-200'
            }`}
          >
            <button 
              onClick={() => onToggle(m.id)}
              className={`mt-1 transition-colors ${m.isCompleted ? 'text-emerald-600' : 'text-gray-300 hover:text-gray-900'}`}
            >
              {m.isCompleted ? <CheckCircle2 size={22} /> : <Circle size={22} />}
            </button>
            <div>
              <p className={`font-bold text-sm ${m.isCompleted ? 'text-gray-400 line-through' : 'text-gray-900'}`}>
                {idx + 1}. {m.title}
              </p>
              <p className="text-xs text-gray-500 mt-1 font-medium">{m.description}</p>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

