const CreateModal = ({ isOpen, onClose, onSubmit, initialType, prefilledTitle }: { 
  isOpen: boolean, 
  onClose: () => void, 
  onSubmit: (entry: Partial<ImpactEntry>) => void,
  initialType?: ImpactType,
  prefilledTitle?: string
}) => {
  const [step, setStep] = useState(1);
  const [type, setType] = useState<ImpactType>(initialType || ImpactType.PROBLEM);
  const [title, setTitle] = useState(prefilledTitle || '');
  const [description, setDescription] = useState('');
  const [aiAnalysis, setAiAnalysis] = useState<any>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (isOpen) {
      if (initialType) setType(initialType);
      if (prefilledTitle) setTitle(prefilledTitle);
    }
  }, [isOpen, initialType, prefilledTitle]);

  const handleNext = async () => {
    if (step === 1) {
      setLoading(true);
      try {
        const result = await analyzeProblem(description);
        setAiAnalysis(result);
        setStep(2);
      } catch (e) {
        console.error(e);
        setStep(2);
      } finally {
        setLoading(false);
      }
    } else {
      const entry: Partial<ImpactEntry> = {
        title,
        description,
        type,
        tags: aiAnalysis?.tags || ['general'],
        location: 'Current Area',
        region: 'Local'
      };
      onSubmit(entry);
      reset();
    }
  };

  const reset = () => {
    setStep(1);
    setTitle('');
    setDescription('');
    setAiAnalysis(null);
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-gray-900/40 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh] border border-gray-200">
        <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
          <h3 className="font-bold text-gray-900 flex items-center gap-2">
            {step === 1 ? <PlusCircle size={20} className="text-gray-900" /> : <Sparkles size={20} className="text-gray-900" />}
            {step === 1 ? 'Start Action' : 'AI-Refined Plan'}
          </h3>
          <button onClick={reset} className="text-gray-400 hover:text-gray-900 p-1">
            <X size={20} />
          </button>
        </div>

        <div className="p-6 overflow-y-auto">
          {step === 1 ? (
            <div className="space-y-4">
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">Category</label>
                <div className="flex gap-4 p-1.5 bg-gray-100 rounded-xl">
                  <button 
                    onClick={() => setType(ImpactType.PROBLEM)}
                    className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${type === ImpactType.PROBLEM ? 'bg-white shadow-sm text-red-600 border border-red-50' : 'text-gray-500'}`}
                  >Report Problem</button>
                  <button 
                    onClick={() => setType(ImpactType.INITIATIVE)}
                    className={`flex-1 py-2 rounded-lg text-sm font-bold transition-all ${type === ImpactType.INITIATIVE ? 'bg-white shadow-sm text-emerald-600 border border-emerald-50' : 'text-gray-500'}`}
                  >Start Initiative</button>
                </div>
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">Title</label>
                <input 
                  value={title}
                  onChange={e => setTitle(e.target.value)}
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-gray-900 outline-none font-medium text-gray-900"
                  placeholder="e.g. Broken playground equipment..."
                />
              </div>
              <div>
                <label className="block text-xs font-bold text-gray-400 uppercase tracking-widest mb-2">Tell the community more</label>
                <textarea 
                  value={description}
                  onChange={e => setDescription(e.target.value)}
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-gray-900 outline-none h-32 resize-none text-gray-900"
                  placeholder="Provide context, evidence, or your vision..."
                />
              </div>
            </div>
          ) : (
            <div className="space-y-5">
              <div className="bg-gray-900 rounded-2xl p-5 text-white shadow-lg">
                <div className="flex items-center gap-2 mb-3">
                  <Shield size={18} />
                  <span className="font-bold text-sm tracking-wide">IMPACT ANALYSIS</span>
                </div>
                <p className="text-gray-300 text-sm mb-4">Our AI analyzed similar cases. This has a high likelihood of community support.</p>
                <div className="flex gap-2 flex-wrap">
                  {aiAnalysis?.tags?.map((tag: string) => (
                    <span key={tag} className="text-[10px] font-black px-2 py-1 bg-white/10 rounded uppercase">#{tag}</span>
                  ))}
                </div>
              </div>

              {aiAnalysis?.suggestedInitiatives && (
                <div>
                  <h4 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-3">Community Roadmap Ideas:</h4>
                  <div className="space-y-3">
                    {aiAnalysis.suggestedInitiatives.map((si: any, i: number) => (
                      <div key={i} className="p-4 border border-gray-200 rounded-2xl hover:border-gray-900 hover:bg-gray-50 transition-all cursor-pointer">
                        <div className="font-bold text-gray-900 text-sm">{si.title}</div>
                        <div className="text-gray-500 text-xs mt-1 leading-relaxed">{si.description}</div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        <div className="p-4 border-t border-gray-100 bg-gray-50 flex justify-end gap-3">
          <button onClick={reset} className="px-6 py-2.5 text-gray-500 font-bold hover:text-gray-900 text-sm">Cancel</button>
          <button 
            disabled={loading || !title || !description}
            onClick={handleNext}
            className="px-8 py-2.5 bg-gray-900 text-white font-bold rounded-xl hover:bg-black shadow-lg disabled:opacity-50 flex items-center gap-2 text-sm"
          >
            {loading ? 'Thinking...' : (step === 1 ? 'Analyze Impact' : 'Publish to Feed')}
            {!loading && <ChevronRight size={18} />}
          </button>
        </div>
      </div>
    </div>
  );
};

